import json

with open('chart.html', 'r') as f:
    html = f.read()

# Find the Vega-Lite spec embedded in the HTML
# Altair embeds it as a JSON object in a script tag or as a JS variable
import re

# Look for the spec - Altair saves embed the spec as JSON
# Common patterns: 'var spec = {...}' or 'vegaEmbed(..., {...}'
match = re.search(r'vegaEmbed\(\s*[\"\\']#\w+[\"\\']\s*,\s*({.*?})\s*,', html, re.DOTALL)
if not match:
    # Try alternative pattern
    match = re.search(r'spec\s*=\s*({.*?});', html, re.DOTALL)

if match:
    spec_str = match.group(1)
    spec = json.loads(spec_str)
else:
    # Try finding any JSON-like structure
    match = re.search(r'\"\$schema\".*?vega-lite', html)
    print('Schema reference found:', bool(match))
    # Parse via extracting between spec = and the next pattern
    match = re.search(r'spec\s*=\s*(.+?);\s*vegaEmbed', html, re.DOTALL)
    if match:
        spec = json.loads(match.group(1))
    else:
        print('Could not extract spec')
        exit(1)

print('=== Top-level keys ===')
print(list(spec.keys()))
print()

# Check mark
if 'mark' in spec:
    print('mark:', spec['mark'])
elif 'layer' in spec:
    print('mark: layer with', len(spec['layer']), 'layers')
    for i, layer in enumerate(spec['layer']):
        print(f'  layer {i} mark:', layer.get('mark'))
elif 'vconcat' in spec or 'hconcat' in spec:
    print('concat chart')
else:
    print('mark: not found directly')
print()

# Check projection
if 'projection' in spec:
    print('projection:', spec['projection'])
elif 'layer' in spec:
    for i, layer in enumerate(spec['layer']):
        if 'projection' in layer:
            print(f'layer {i} projection:', layer['projection'])
print()

# Check transforms
def find_transforms(obj, path=''):
    results = []
    if isinstance(obj, dict):
        if 'transform' in obj:
            results.append((path, obj['transform']))
        for k, v in obj.items():
            results.extend(find_transforms(v, f'{path}.{k}'))
    elif isinstance(obj, list):
        for i, v in enumerate(obj):
            results.extend(find_transforms(v, f'{path}[{i}]'))
    return results

transforms = find_transforms(spec)
print('=== Transforms found ===')
for path, tlist in transforms:
    print(f'  {path}:')
    for t in tlist:
        print(f'    {t}')
print()

# Check params
def find_params(obj, path=''):
    results = []
    if isinstance(obj, dict):
        if 'params' in obj:
            results.append((path, obj['params']))
        for k, v in obj.items():
            results.extend(find_params(v, f'{path}.{k}'))
    elif isinstance(obj, list):
        for i, v in enumerate(obj):
            results.extend(find_params(v, f'{path}[{i}]'))
    return results

params = find_params(spec)
print('=== Params found ===')
for path, plist in params:
    for p in plist:
        print(f'  {path}: {json.dumps(p, indent=4)}')
print()

# Check encoding
def find_encoding(obj, path=''):
    results = []
    if isinstance(obj, dict):
        if 'encoding' in obj:
            results.append((path, obj['encoding']))
        for k, v in obj.items():
            results.extend(find_encoding(v, f'{path}.{k}'))
    elif isinstance(obj, list):
        for i, v in enumerate(obj):
            results.extend(find_encoding(v, f'{path}[{i}]'))
    return results

encodings = find_encoding(spec)
print('=== Encodings found ===')
for path, enc in encodings:
    print(f'  {path}:')
    for ch, cfg in enc.items():
        print(f'    {ch}: {json.dumps(cfg)}')
